		}
	}
	resolvedTitle := displayName
	if resolvedTitle == "" {
		resolvedTitle = title
	}
	if resolvedTitle == "" {
		resolvedTitle = prompt
	}
	if resolvedTitle == "" {
		resolvedTitle = "new agent: " + row.ID
	}
	title = resolvedTitle
	kind := rowKind(row.Metadata)

	return Session{
