	ProjectPath   string
	ProjectName   string
	AgentPlugin   string
	WorkspacePath string
	ZellijSession string

	// PID is the agent process id, when known. Zero if unset.
	PID int64

	// Metadata holds plugin-specific fields (codex thread id, etc.) as a
