		return shellQuote(direnv) + " exec " + shellQuote(sourceRoot) + " go run ."
	}
	return "cd " + shellQuote(sourceRoot) + " && go run ."
}

func shellQuote(value string) string {
	return "'" + strings.ReplaceAll(value, "'", "'\\''") + "'"
}

